// TypeScript implementation for Intersection Types
interface IntersectionTypesPayload {
  id: number;
  title: string;
  status: 'active' | 'pending';
}

function processIntersectionTypes(item: IntersectionTypesPayload): string {
  return `[${item.id}] ${item.title}: ${item.status}`;
}

console.log(processIntersectionTypes({ id: 1, title: 'Intersection Types', status: 'active' }));

